input.new_string:
.code-content {
  margin: 0;
  padding: 12px 16px;
  overflow-x: auto;
  background-color: #f8f9fa;
  font-size: 13px;
  line-height: 1.6;
  white-space: pre;

  code {
    display: block;
    white-space: pre;
    font-family: 'SF Mono', 'Fira Code', 'Consolas', monospace;
    background: transparent;
  }
}

input.old_string:
.code-content {
  margin: 0;
  padding: 12px 16px;
  overflow-x: auto;
  background-color: #f8f9fa;
  font-size: 13px;
  line-height: 1.6;

  code {
    display: block;
    white-space: pre-wrap;
    word-break: break-word;
    font-family: 'SF Mono', 'Fira Code', 'Consolas', monospace;
    background: transparent;
  }
}
